module ripple_carry_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] Sum,
    output Cout
);
    wire [3:0] carry;

    // Full Adder for bit 0
  assign {Cout, Sum[3]} = A[3] + B[3] + carry[2];
    // Full Adder for bit 1
  assign {carry[2], Sum[2]} = A[2] + B[2] + carry[1];
    // Full Adder for bit 2
  assign {carry[1], Sum[1]} = A[1] + B[1] + carry[0];
    // Full Adder for bit 3
  assign {carry[0], Sum[0]} = A[0] + B[0] + Cin;
endmodule

module ripple_carry_adder (
    input [3:0] A,
    input [3:0] B,
    input Cin,
    output [3:0] Sum,
    output Cout
);
    wire C1, C2, C3;

    // Full adder logic
  assign Cout = (A[3] & B[3]) | (C3 & (A[3] ^ B[3]));
  assign Sum[3] = A[3] ^ B[3] ^ C3;

  assign C3 = (A[2] & B[2]) | (C2 & (A[2] ^ B[2]));
  assign Sum[2] = A[2] ^ B[2] ^ C2;

  assign C2 = (A[1] & B[1]) | (C1 & (A[1] ^ B[1]));
  assign Sum[1] = A[1] ^ B[1] ^ C1;

  assign C1 = (A[0] & B[0]) | (Cin & (A[0] ^ B[0]));
  assign Sum[0] = A[0] ^ B[0] ^ Cin;
endmodule

module KoggeStoneAdder (
    input [3:0] A,
    input [3:0] B,
    output [4:0] Sum
);

wire [3:0] G; // Generate
wire [3:0] P; // Propagate
wire [3:0] C; // Carry

// Generate and Propagate
  assign Sum[4] = G[3] | (P[3] & C[3]);
  assign Sum[3] = P[3] ^ C[3];

// Carry computation
  assign Sum[2] = P[2] ^ C[2];
  assign Sum[1] = P[1] ^ C[1];
  assign Sum[0] = P[0] ^ C[0];
  assign C[3] = G[2] | (P[2] & G[1]) | (P[2] & P[1] & G[0]) | (P[2] & P[1] & P[0] & C[0]);

// Final sum output
  assign C[2] = G[1] | (P[1] & G[0]) | (P[1] & P[0] & C[0]);
  assign C[1] = G[0] | (P[0] & C[0]);
  assign C[0] = 0;
