);
    // Gradient of f(x) = (x - 3)^2 is 2*(x - 3)
    wire signed [3:0] gradient;
  assign x_next = x_current - gradient;

    // Update x: x_next = x_current - learning_rate * gradient
  assign gradient = 2 * (x_current - 4'b0011);

endmodule

