        end
        else
        begin
            if (valid_read)     head <= next_head;
            if (valid_write)    tail <= next_tail;
        end
    end

  assign ram_waddr = tail;
  assign ram_wen = valid_write;
  assign full = (head == tail && empty == 1'b0) ? 1'b1 : 1'b0;

