module RMON_CTRL (
Clk             ,      
Reset           ,      
Reg_apply_0     ,      
Reg_addr_0      ,      
Reg_data_0      ,      
Reg_next_0      ,      
Reg_apply_1     ,      
Reg_addr_1      ,      
Reg_data_1      ,      
Reg_next_1      ,      
Addra               ,  
Dina                ,  
Douta               ,  
Wea                 ,  
CPU_rd_addr     ,  
CPU_rd_apply        ,  
CPU_rd_grant        ,
CPU_rd_dout
);
input           Clk             ;
input           Reset           ;
input           Reg_apply_0     ;
input   [4:0]   Reg_addr_0      ;
input   [15:0]  Reg_data_0      ;
output          Reg_next_0      ;
input           Reg_apply_1     ;
input   [4:0]   Reg_addr_1      ;
input   [15:0]  Reg_data_1      ;
output          Reg_next_1      ;
output  [5:0]   Addra               ;
output  [31:0]  Dina                ;
input   [31:0]  Douta               ;
output          Wea                 ;
input   [5:0]   CPU_rd_addr         ;
input           CPU_rd_apply        ;
output          CPU_rd_grant        ;
output  [31:0]  CPU_rd_dout         ;
parameter       StateCPU        =4'd00;
parameter       StateMAC0       =4'd01;
parameter       StateMAC1       =4'd02;
reg [3:0]       CurrentState ;
reg [3:0]       NextState;
reg [3:0]       CurrentState_reg;
reg [4:0]       StepCounter;
reg [31:0]      DoutaReg;
reg [5:0]       Addra               ;
reg [31:0]      Dina;
reg             Reg_next_0      ;
reg             Reg_next_1      ;
reg             Write;
reg             Read;
reg             Pipeline;
reg [31:0]      CPU_rd_dout         ;
reg             CPU_rd_apply_reg    ;
always @(posedge Clk or posedge Reset)
    if (Reset)
        CurrentState    <=StateMAC0;
    else
        CurrentState    <=NextState;
always @(posedge Clk or posedge Reset)
    if (Reset)  
        CurrentState_reg    <=StateMAC0;
    else if(CurrentState!=StateCPU)
        CurrentState_reg    <=CurrentState;
always @(CurrentState or CPU_rd_apply_reg or Reg_apply_0 or CurrentState_reg
                                       or Reg_apply_1   
                                       or StepCounter
                                       )
    case(CurrentState)
        StateMAC0:
            if(!Reg_apply_0&&CPU_rd_apply_reg)
                NextState   =StateCPU;
            else if(!Reg_apply_0)
                NextState   =StateMAC1;
            else
                NextState   =CurrentState;
        StateMAC1:
            if(!Reg_apply_1&&CPU_rd_apply_reg)
                NextState   =StateCPU;
            else if(!Reg_apply_1)
                NextState   =StateMAC0;
            else
                NextState   =CurrentState;
        StateCPU:
            if (StepCounter==3)
                case (CurrentState_reg)
                    StateMAC0   :NextState  =StateMAC0 ;
                    StateMAC1   :NextState  =StateMAC1 ;
                    default     :NextState  =StateMAC0;
                endcase
            else
                NextState   =CurrentState;
        default:
                NextState   =StateMAC0;
    endcase
always @(posedge Clk or posedge Reset)
    if (Reset)
        StepCounter     <=0;
    else if(NextState!=CurrentState)
        StepCounter     <=0;
    else if (StepCounter!=4'hf)
        StepCounter     <=StepCounter + 1;
always @(StepCounter)
    if( StepCounter==1||StepCounter==4||
        StepCounter==7||StepCounter==10)
        Read    =1;
    else
        Read    =0;
always @(StepCounter or CurrentState)
    if( StepCounter==2||StepCounter==5||
        StepCounter==8||StepCounter==11)
        Pipeline    =1;
    else
        Pipeline    =0;
always @(StepCounter or CurrentState)
    if( StepCounter==3||StepCounter==6||
        StepCounter==9||StepCounter==12)
        Write   =1;
    else
        Write   =0;
always @(posedge Clk or posedge Reset)
    if (Reset)
        DoutaReg        <=0;
    else if (Read)
        DoutaReg        <=Douta;
always @(*)
    case(CurrentState)
        StateMAC0 :     Addra={1'd0 ,Reg_addr_0 };
        StateMAC1 :     Addra={1'd1 ,Reg_addr_1 };
        StateCPU:       Addra=CPU_rd_addr;
        default:        Addra=0;
        endcase
always @(posedge Clk or posedge Reset)
    if (Reset)
        Dina    <=0;
    else 
        case(CurrentState)
            StateMAC0 :     Dina<=Douta+Reg_data_0 ;
            StateMAC1 :     Dina<=Douta+Reg_data_1 ;
            StateCPU:       Dina<=0;
            default:        Dina<=0;
        endcase
  assign CPU_rd_grant =!CPU_rd_apply_reg;
always @(CurrentState or Pipeline)
    if(CurrentState==StateMAC0)
        Reg_next_0  =Pipeline;
    else
        Reg_next_0  =0;
always @(CurrentState or Pipeline)
    if(CurrentState==StateMAC1)
        Reg_next_1  =Pipeline;
    else
        Reg_next_1  =0;     
reg     CPU_rd_apply_dl1;
reg     CPU_rd_apply_dl2;
always @ (posedge Clk or posedge Reset)
    if (Reset)
        begin
        CPU_rd_apply_dl1        <=0;
        CPU_rd_apply_dl2        <=0;
        end
    else
        begin
        CPU_rd_apply_dl1        <=CPU_rd_apply;
        CPU_rd_apply_dl2        <=CPU_rd_apply_dl1;
        end     
always @ (posedge Clk or posedge Reset)
    if (Reset)
        CPU_rd_apply_reg    <=0;
    else if (CPU_rd_apply_dl1&!CPU_rd_apply_dl2)
        CPU_rd_apply_reg    <=1;
    else if (CurrentState==StateCPU&&Write)
        CPU_rd_apply_reg    <=0;
  assign  Wea     =Write;
always @ (posedge Clk or posedge Reset)
    if (Reset)
        CPU_rd_dout     <=0;
    else if (Pipeline&&CurrentState==StateCPU)
        CPU_rd_dout     <=Douta;        
endmodule

module zzecc_sctag_30b_cor ( din, parity, dout, corrected_bit ) ;
input  [23:0] din ;
input  [4:0]  parity ;
output [23:0] dout ;
output [4:0]  corrected_bit ;
wire   [23:0] dout ;
wire   [4:0]  corrected_bit ;
wire          p1 ;
wire          p2 ;
wire          p4 ;
wire          p8 ;
wire          p16 ;
wire [23:0]   error_bit ;
  assign  corrected_bit = {p16, p8, p4, p2, p1} ;
             din[0]  ^ din[1]  ^ din[3]  ^ din[4]  ^ din[6]  ^ din[8]  ^
             din[10] ^ din[11] ^ din[13] ^ din[15] ^ din[17] ^ din[19] ^
             din[21] ^ din[23] ;
  assign  dout          = din ^ error_bit ;
             din[0]  ^ din[2]  ^ din[3]  ^ din[5]  ^ din[6]  ^ din[9]  ^
             din[10] ^ din[12] ^ din[13] ^ din[16] ^ din[17] ^ din[20] ^
             din[21] ;
  assign  error_bit[23] =  p16 &  p8 &  p4 & !p2 &  p1 ;
             din[1]  ^ din[2]  ^ din[3]  ^ din[7]  ^ din[8]  ^ din[9]  ^
             din[10] ^ din[14] ^ din[15] ^ din[16] ^ din[17] ^ din[22] ^
             din[23] ;
  assign  error_bit[22] =  p16 &  p8 &  p4 & !p2 & !p1 ;
             din[4]  ^ din[5]  ^ din[6]  ^ din[7]  ^ din[8]  ^ din[9]  ^
             din[10] ^ din[18] ^ din[19] ^ din[20] ^ din[21] ^ din[22] ^
             din[23] ;
  assign  error_bit[21] =  p16 &  p8 & !p4 &  p2 &  p1 ;
             din[11] ^ din[12] ^ din[13] ^ din[14] ^ din[15] ^ din[16] ^
             din[17] ^ din[18] ^ din[19] ^ din[20] ^ din[21] ^ din[22] ^
             din[23] ;
  assign  error_bit[20] =  p16 &  p8 & !p4 &  p2 & !p1 ;
  assign  error_bit[19] =  p16 &  p8 & !p4 & !p2 &  p1 ;
  assign  error_bit[18] =  p16 &  p8 & !p4 & !p2 & !p1 ;
  assign  error_bit[17] =  p16 & !p8 &  p4 &  p2 &  p1 ;
  assign  error_bit[16] =  p16 & !p8 &  p4 &  p2 & !p1 ;
  assign  error_bit[15] =  p16 & !p8 &  p4 & !p2 &  p1 ;
  assign  error_bit[14] =  p16 & !p8 &  p4 & !p2 & !p1 ;
  assign  error_bit[13] =  p16 & !p8 & !p4 &  p2 &  p1 ;
  assign  error_bit[12] =  p16 & !p8 & !p4 &  p2 & !p1 ;
  assign  error_bit[11] =  p16 & !p8 & !p4 & !p2 &  p1 ;
  assign  error_bit[10] = !p16 &  p8 &  p4 &  p2 &  p1 ;
  assign  error_bit[9]  = !p16 &  p8 &  p4 &  p2 & !p1 ;
  assign  error_bit[8]  = !p16 &  p8 &  p4 & !p2 &  p1 ;
  assign  error_bit[7]  = !p16 &  p8 &  p4 & !p2 & !p1 ;
  assign  error_bit[6]  = !p16 &  p8 & !p4 &  p2 &  p1 ;
  assign  error_bit[5]  = !p16 &  p8 & !p4 &  p2 & !p1 ;
  assign  error_bit[4]  = !p16 &  p8 & !p4 & !p2 &  p1 ;
  assign  error_bit[3]  = !p16 & !p8 &  p4 &  p2 &  p1 ;
  assign  error_bit[2]  = !p16 & !p8 &  p4 &  p2 & !p1 ;
  assign  error_bit[1]  = !p16 & !p8 &  p4 & !p2 &  p1 ;
  assign  error_bit[0]  = !p16 & !p8 & !p4 &  p2 &  p1 ;
  assign p16 = parity[4] ^
             din[11] ^ din[12] ^ din[13] ^ din[14] ^ din[15] ^ din[16] ^
             din[17] ^ din[18] ^ din[19] ^ din[20] ^ din[21] ^ din[22] ^
             din[23] ;
  assign p8  = parity[3] ^
             din[4]  ^ din[5]  ^ din[6]  ^ din[7]  ^ din[8]  ^ din[9]  ^
             din[10] ^ din[18] ^ din[19] ^ din[20] ^ din[21] ^ din[22] ^
             din[23] ;
  assign p4  = parity[2] ^
             din[1]  ^ din[2]  ^ din[3]  ^ din[7]  ^ din[8]  ^ din[9]  ^
             din[10] ^ din[14] ^ din[15] ^ din[16] ^ din[17] ^ din[22] ^
             din[23] ;
  assign p2  = parity[1] ^
             din[0]  ^ din[2]  ^ din[3]  ^ din[5]  ^ din[6]  ^ din[9]  ^
             din[10] ^ din[12] ^ din[13] ^ din[16] ^ din[17] ^ din[20] ^
             din[21] ;
  assign p1  = parity[0] ^
             din[0]  ^ din[1]  ^ din[3]  ^ din[4]  ^ din[6]  ^ din[8]  ^
             din[10] ^ din[11] ^ din[13] ^ din[15] ^ din[17] ^ din[19] ^
             din[21] ^ din[23] ;
endmodule

module lcpmult(in1, in2, out);
   input [0:4] in1, in2; 
   output [0:4] out;
   wire [4:0] intvald; 
   wire [3:0] intvale; 
   wire intvale_0ax; 
  assign out[4] = intvald[4] ^ intvale[2];
  assign out[3] = (intvald[3] ^ intvale[1]) ^ intvale[3];
  assign out[2] = (intvald[2] ^ intvale[2]) ^ intvale_0ax;
  assign out[1] = intvald[1] ^ intvale[1];
  assign out[0] = intvald[0] ^ intvale_0ax;
                        ^ ((in1[1] & in2[3]) ^ (in1[0] & in2[4])); 
  assign intvale_0ax = (intvale[0] ^ intvale[3]);
  assign intvale[3] = in1[4] & in2[4];
  assign intvale[2] = (in1[4] & in2[3]) ^ (in1[3] & in2[4]);
  assign intvale[1] = ((in1[4] & in2[2]) ^ (in1[3] & in2[3])) ^ (in1[2] & in2[4]);
  assign intvale[0] = ((in1[4] & in2[1]) ^ (in1[3] & in2[2])) ^ ((in1[2] & in2[3]) ^ (in1[1] & in2[4]));
  assign intvald[4] = (((in1[4] & in2[0]) ^ (in1[3] & in2[1])) ^ (in1[2] & in2[2]))
                        ^ ((in1[1] & in2[3]) ^ (in1[0] & in2[4]));
  assign intvald[3] = ((in1[3] & in2[0]) ^ (in1[2] & in2[1])) ^ ((in1[1] & in2[2]) ^ (in1[0] & in2[3]));
  assign intvald[2] = (in1[2] & in2[0]) ^ ((in1[1] & in2[1]) ^ (in1[0] & in2[2]));
  assign intvald[1] = (in1[1] & in2[0]) ^ (in1[0] & in2[1]);
  assign intvald[0] = in1[0] & in2[0];
 endmodule

module RegisterFile(
    input  clock,
    input  reset,
    input  [4:0]  ReadReg1, ReadReg2, WriteReg,
    input  [31:0] WriteData,
    input  RegWrite,
    output [31:0] ReadData1, ReadData2
    );
    reg [31:0] registers [1:31];
    integer i;
    initial begin
        for (i=1; i<32; i=i+1) begin
            registers[i] <= 0;
        end
    end
    always @(posedge clock) begin
        if (reset) begin
            for (i=1; i<32; i=i+1) begin
                registers[i] <= 0;
            end
        end
        else begin
            if (WriteReg != 0)
                registers[WriteReg] <= (RegWrite) ? WriteData : registers[WriteReg];
        end
    end
  assign ReadData2 = (ReadReg2 == 0) ? 32'h00000000 : registers[ReadReg2];
  assign ReadData1 = (ReadReg1 == 0) ? 32'h00000000 : registers[ReadReg1];
endmodule

module avr_io_out
 (	input clk,
