reg     [7:0]   Rxd_dl2             ;
reg             Crs_dl1             ;
reg             Col_dl1             ;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)
        begin
        MTxD_dl1            <=0;
        MTxEn_dl1           <=0;
        end  
    else
        begin
        MTxD_dl1            <=MTxD  ;
        MTxEn_dl1           <=MTxEn ;
        end 
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)   
        Tx_odd_data_ptr     <=0;
    else if (!MTxD_dl1)
        Tx_odd_data_ptr     <=0;
    else 
        Tx_odd_data_ptr     <=!Tx_odd_data_ptr;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)  
        Txd                 <=0;
    else if(Speed[2]&&MTxEn_dl1)
        Txd                 <=MTxD_dl1;
    else if(MTxEn_dl1&&!Tx_odd_data_ptr)
        Txd                 <={4'b0,MTxD_dl1[3:0]};
    else if(MTxEn_dl1&&Tx_odd_data_ptr)
        Txd                 <={4'b0,MTxD_dl1[7:4]};
    else
        Txd                 <=0;
always @ (posedge MAC_tx_clk or posedge Reset)
    if (Reset)  
        Tx_en               <=0;
    else if(MTxEn_dl1)
        Tx_en               <=1;    
    else
        Tx_en               <=0;
  assign MCRS     =Crs_dl1        ;
always @ (posedge MAC_rx_clk or posedge Reset)
    if (Reset)  
        begin
        Rx_er_dl1           <=0;
        Rx_dv_dl1           <=0;
        Rx_dv_dl2           <=0 ;
        Rxd_dl1             <=0;
        Rxd_dl2             <=0;
        Crs_dl1             <=0;
        Col_dl1             <=0;
        end
    else
        begin
        Rx_er_dl1           <=Rx_er     ;
        Rx_dv_dl1           <=Rx_dv     ;
        Rx_dv_dl2           <=Rx_dv_dl1 ;
        Rxd_dl1             <=Rxd       ;
        Rxd_dl2             <=Rxd_dl1   ;
        Crs_dl1             <=Crs       ;
        Col_dl1             <=Col       ;
        end     
  assign MRxErr   =Rx_er_dl1      ;
  assign Tx_er=0;
always @ (posedge MAC_rx_clk or posedge Reset)
    if (Reset)  
        MCrs_dv         <=0;
    else if(Line_loop_en)
        MCrs_dv         <=Tx_en;
    else if(Rx_dv_dl2)
        MCrs_dv         <=1;
    else
        MCrs_dv         <=0;
always @ (posedge MAC_rx_clk or posedge Reset)
    if (Reset)   
        Rx_odd_data_ptr     <=0;
    else if (!Rx_dv_dl1)
        Rx_odd_data_ptr     <=0;
    else 
        Rx_odd_data_ptr     <=!Rx_odd_data_ptr;
always @ (posedge MAC_rx_clk or posedge Reset)
    if (Reset)  
        MRxD            <=0;
    else if(Line_loop_en)
        MRxD            <=Txd;
    else if(Speed[2]&&Rx_dv_dl2)
        MRxD            <=Rxd_dl2;
    else if(Rx_dv_dl1&&Rx_odd_data_ptr)
        MRxD            <={Rxd_dl1[3:0],Rxd_dl2[3:0]};
endmodule

module DECODER ( INA, INB, INC, TWOPOS, TWONEG, ONEPOS, ONENEG );
input  INA;
input  INB;
input  INC;
output TWOPOS;
output TWONEG;
output ONEPOS;
output ONENEG;
  assign ONENEG = (INA & ( ~ INB) & INC) | (INC & INB & ( ~ INA));
  assign ONEPOS = (( ~ INA) & INB & ( ~ INC)) | (( ~ INC) & ( ~ INB) & INA);
  assign TWONEG =  ~ ( ~ (( ~ INA) & ( ~ INB) & INC));
  assign TWOPOS =  ~ ( ~ (INA & INB & ( ~ INC)));
endmodule

module gfx_wbm_write (clk_i, rst_i,
                      cyc_o, stb_o, cti_o, bte_o, we_o, adr_o, sel_o, ack_i, err_i, dat_o, sint_o,
                      write_i, ack_o,
                      render_addr_i, render_sel_i, render_dat_i);
  input         clk_i;    
  input         rst_i;    
  output reg    cyc_o;    
  output        stb_o;    
  output [ 2:0] cti_o;    
  output [ 1:0] bte_o;    
  output        we_o;     
  output [31:0] adr_o;    
  output [ 3:0] sel_o;    
  input         ack_i;    
  input         err_i;    
  output [31:0] dat_o;    
  output        sint_o;     
  input         write_i;
  output reg    ack_o;
  input [31:2]  render_addr_i;
  input [ 3:0]  render_sel_i;
  input [31:0]  render_dat_i;
  assign bte_o  = 2'b00;
  assign cti_o  = 3'b000;
  assign stb_o  = 1'b1;
  assign we_o   = 1'b1;
  assign sint_o = err_i;
  assign sel_o  = render_sel_i;
  assign dat_o  = render_dat_i;
  assign adr_o  = {render_addr_i, 2'b00};
  always @(posedge clk_i or posedge rst_i)
  begin
    if(rst_i)
    begin
      ack_o <= 1'b0;
      cyc_o <= 1'b0;
    end
    else
    begin
      cyc_o <= ack_i   ? 1'b0 : 
               write_i ? 1'b1 :
               cyc_o;
      ack_o <= ack_i; 
    end
  end
endmodule

