module gng_smul_16_18_sadd_37 (
    input clk,                  
    input [15:0] a,             
    input [17:0] b,             
    input [36:0] c,             
    output [37:0] p             
);
reg signed [15:0] a_reg;
reg signed [17:0] b_reg;
reg signed [36:0] c_reg;
reg signed [33:0] prod;
wire signed [37:0] sum;
reg [37:0] result;
always @ (posedge clk) begin
    a_reg <= a;
    b_reg <= b;
    c_reg <= c;
end
always @ (posedge clk) begin
    prod <= a_reg * b_reg;
end
  assign p = result;
always @ (posedge clk) begin
    result <= sum;
end
  assign sum = c_reg + prod;
endmodule

module alu_mux_2(
