wire	SYNTHESIZED_WIRE_1;
wire	SYNTHESIZED_WIRE_2;
  assign	SYNTHESIZED_WIRE_0 =  ~sel1;
  assign	out = SYNTHESIZED_WIRE_1 | SYNTHESIZED_WIRE_2;
