module LED(
    input  clock,
    input  reset,
    input  [14:0] dataIn,
    input  [7:0] IP,
    input  Write,
    input  Read,
    output [13:0] dataOut,
    output reg Ack,
    output [13:0] LED
    );
    reg  [13:0] data;
    reg  useInterrupts;
    always @(posedge clock) begin
        data <= (reset) ? 14'b0 : ((Write) ? dataIn[13:0] : data);
        useInterrupts <= (reset) ? 0 : ((Write) ? dataIn[14] : useInterrupts);
    end
    always @(posedge clock) begin
        Ack <= (reset) ? 0 : (Write | Read);
    end
  assign dataOut = data;
  assign LED = (useInterrupts) ? {6'b0, IP[7:0]} : data;
endmodule

module bmc100
(
   rx_pair,
   path_0_bmc,
   path_1_bmc
);
   input    [1:0] rx_pair;
   output   [1:0] path_0_bmc;
   output   [1:0] path_1_bmc;
  assign path_1_bmc    =  {(tmp10 & tmp11),(tmp10 ^ tmp11)};
  assign path_0_bmc    =  {(tmp00 & tmp01),(tmp00 ^ tmp01)};
  assign tmp11         =  (rx_pair[1] ^ 1'b1);
  assign tmp10         =  (rx_pair[0] ^ 1'b1);
  assign tmp01         =  (rx_pair[1] ^ 1'b0);
  assign tmp00         =  (rx_pair[0] ^ 1'b0);
endmodule

module move_cell(
    input r,
    input b,
    input fw_in,
    input bw_in,
    output fw_out,
    output bw_out,
    input pulse,
    output r_out,
    output b_out
    );
reg r_out_reg;
reg b_out_reg;
always @( * ) begin
	if ( bw_in && fw_in ) begin
		b_out_reg = 1;
		r_out_reg = 0;
	end
	else begin
		b_out_reg = b;
		r_out_reg = r;
	end
end
  assign	b_out = b_out_reg;
  assign 	r_out = r_out_reg;
  assign	bw_out = bw_in || (b && fw_in);
  assign 	fw_out = pulse || (r && fw_in);
endmodule

