module adder_4bit_carry (
  input clk,
  input rst,
  input [3:0] a,
  input [3:0] b,
  input cin,
  output [3:0] sum,
  output cout
);

  reg [3:0] sum_reg;
  reg cout_reg;

  always @(posedge clk) begin
    if (rst) begin
      sum_reg <= 4'b0;
      cout_reg <= 1'b0;
    end else begin
      {cout_reg, sum_reg} <= a + b + cin;
    end
  end

  assign cout = cout_reg;
  assign sum = sum_reg;

endmodule

