module my_module (
    input in1,
    input in2,
    input in3,
    input clk,
    input reset,
    output out1,
    output out2
);

    reg out1_reg;
    reg out2_reg;

    always @(posedge clk) begin
        if (reset) begin
            out1_reg <= 1'b0;
            out2_reg <= 1'b0;
        end else begin
            out1_reg <= in1 ^ in2;
            out2_reg <= in2 & in3;
        end
    end

  assign out2 = out2_reg;
  assign out1 = out1_reg;

endmodule

module mux4to1 (
    input [3:0] in,
    input [1:0] sel,
    output reg out
);

    wire sel0_inv, sel1_inv;

  assign sel1_inv = ~sel[1];
  assign sel0_inv = ~sel[0];

    always @(*) begin
        if (sel == 2'b00) begin
            out = in[0];
        end else if (sel == 2'b01) begin
            out = in[1];
        end else if (sel == 2'b10) begin
            out = in[2];
        end else begin
            out = in[3];
        end
    end

endmodule

