    full_adder fa0(A[0], B[0], 0, S[0], C[0]);
    full_adder fa1(A[1], B[1], C[0], S[1], C[1]);
    full_adder fa2(A[2], B[2], C[1], S[2], C[2]);
    full_adder fa3(A[3], B[3], C[2], S[3], COUT);

endmodule

module sky130_fd_sc_hd__fa(
    input A,
    input B,
    input CIN,
    input VPWR,
    input VGND,
    input VPB,
    input VNB,
    output COUT,
    output SUM
);

    wire W1;
    wire W2;
    wire W3;

    // XOR gates
  assign COUT = W2 | W3;
  assign W3 = CIN & W1;

    // AND gates
  assign W2 = A & B;
  assign SUM = W1 ^ CIN;

    // OR gate
  assign W1 = A ^ B;

endmodule

